#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Process structure representing a process in the system */
typedef struct {
 int pid; /* Process ID */
 int size; /* Size in pages */
 int priority; /* Process priority (higher = more important) */
 int frames_allocated; /* Frames assigned to this process */
} Process;

/* Structure to hold allocation results */
typedef struct {
 int pid;
 int frames;
} FrameAllocation;

/* Calculate equal allocation - divide frames evenly */
void equal_allocation(int total_frames, Process *processes, int n, FrameAllocation *result) {
 if (n == 0) return;

 int base_frames = total_frames / n;
 int remainder = total_frames % n;

 for (int i = 0; i < n; i++) {
 result[i].pid = processes[i].pid;
 /* Distribute remainder to first few processes */
 result[i].frames = base_frames + (i < remainder ? 1 : 0);
 processes[i].frames_allocated = result[i].frames;
 }
}

/* Calculate proportional allocation based on process size */
void proportional_allocation(int total_frames, Process *processes, int n, FrameAllocation *result) {
 if (n == 0) return;

 int total_size = 0;
 for (int i = 0; i < n; i++) {
 total_size += processes[i].size;
 }

 if (total_size == 0) {
 equal_allocation(total_frames, processes, n, result);
 return;
 }

 int allocated = 0;

 /* First pass: allocate floor values */
 for (int i = 0; i < n; i++) {
 double share = ((double)processes[i].size / total_size) * total_frames;
 result[i].frames = (int)share;
 result[i].pid = processes[i].pid;
 allocated += result[i].frames;
 }

 /* Second pass: distribute remainder to largest process */
 int remainder = total_frames - allocated;
 if (remainder > 0) {
 int max_idx = 0;
 for (int i = 1; i < n; i++) {
 if (processes[i].size > processes[max_idx].size) {
 max_idx = i;
 }
 }
 result[max_idx].frames += remainder;
 }

 /* Update process records */
 for (int i = 0; i < n; i++) {
 processes[i].frames_allocated = result[i].frames;
 }
}

/* Calculate priority-based allocation */
void priority_allocation(int total_frames, Process *processes, int n, FrameAllocation *result) {
 if (n == 0) return;

 int total_priority = 0;
 for (int i = 0; i < n; i++) {
 total_priority += processes[i].priority;
 }

 if (total_priority == 0) {
 equal_allocation(total_frames, processes, n, result);
 return;
 }

 int allocated = 0;

 /* Allocate based on priority proportion */
 for (int i = 0; i < n; i++) {
 double share = ((double)processes[i].priority / total_priority) * total_frames;
 result[i].frames = (int)share;
 result[i].pid = processes[i].pid;
 allocated += result[i].frames;
 }

 /* Handle remainder - give to highest priority process */
 int remainder = total_frames - allocated;
 if (remainder > 0) {
 int max_priority_idx = 0;
 for (int i = 1; i < n; i++) {
 if (processes[i].priority > processes[max_priority_idx].priority) {
 max_priority_idx = i;
 }
 }
 result[max_priority_idx].frames += remainder;
 }

 /* Update process records */
 for (int i = 0; i < n; i++) {
 processes[i].frames_allocated = result[i].frames;
 }
}

/* Display allocation results */
void display_allocation(const char *scheme, FrameAllocation *result, int n) {
 printf("\n%s:\n", scheme);
 printf("----------------------------------------\n");
 for (int i = 0; i < n; i++) {
 printf(" Process %d: %d frames\n", result[i].pid, result[i].frames);
 }
}

/* Main function - demonstration */
int main() {
 /* Create sample processes */
 Process processes[] = {
 {1, 100, 3, 0}, /* PID=1, size=100 pages, priority=3 */
 {2, 50, 2, 0}, /* PID=2, size=50 pages, priority=2 */
 {3, 25, 1, 0} /* PID=3, size=25 pages, priority=1 */
 };

 int n = sizeof(processes) / sizeof(processes[0]);
 int total_frames = 60;

 printf("========================================\n");
 printf(" FRAME ALLOCATION CALCULATOR\n");
 printf("========================================\n");
 printf("Total Available Frames: %d\n", total_frames);
 printf("Number of Processes: %d\n", n);
 printf("\nProcess Details:\n");
 for (int i = 0; i < n; i++) {
 printf(" P%d: size=%d pages, priority=%d\n", 
 processes[i].pid, processes[i].size, processes[i].priority);
 }

 FrameAllocation *result = malloc(n * sizeof(FrameAllocation));

 /* Test Equal Allocation */
 equal_allocation(total_frames, processes, n, result);
 display_allocation("1. EQUAL ALLOCATION", result, n);

 /* Reset process allocations */
 for (int i = 0; i < n; i++) {
 processes[i].frames_allocated = 0;
 }

 /* Test Proportional Allocation */
 proportional_allocation(total_frames, processes, n, result);
 display_allocation("2. PROPORTIONAL ALLOCATION", result, n);

 /* Reset process allocations */
 for (int i = 0; i < n; i++) {
 processes[i].frames_allocated = 0;
 }

 /* Test Priority Allocation */
 priority_allocation(total_frames, processes, n, result);
 display_allocation("3. PRIORITY ALLOCATION", result, n);

 free(result);
 return 0;
}
